func TestFormatAuthorizationHeader(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  string
	}{
		{"empty", "", ""},
		{"bare token", "abc123", "Bearer abc123"},
		{"already bearer", "Bearer abc123", "Bearer abc123"},
		{"already basic", "Basic dXNlcjpwYXNz", "Basic dXNlcjpwYXNz"},
		{"lower bearer", "bearer abc123", "bearer abc123"},
		{"trim spaces", "  abc123  ", "Bearer abc123"},
		{"basic lower", "basic dXNlcjpwYXNz", "basic dXNlcjpwYXNz"},
		{"all uppercase", "BEARER xyz", "BEARER xyz"},
		{"token with spaces inside", "  token with spaces  ", "Bearer token with spaces"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := FormatAuthorizationHeader(tt.input)
			if got != tt.want {
				t.Errorf("FormatAuthorizationHeader(%q) = %q, want %q", tt.input, got, tt.want)
			}
		})
	}
}

