func TestForwardAndParseResponse(t *testing.T) {
	t.Run("success", func(t *testing.T) {
		ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusOK)
			w.Write([]byte(`{"ok":true}`))
		}))
		defer ts.Close()

		result, err := ForwardAndParseResponse(context.Background(), ts.URL, "GET", "/api/test", map[string]interface{}{}, []string{}, "", "TestTool")
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if result == nil {
			t.Fatal("result is nil")
		}
		if result.IsError {
			t.Error("unexpected error result")
		}
	})

	t.Run("upstream error 500", func(t *testing.T) {
		ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			w.WriteHeader(http.StatusInternalServerError)
			w.Write([]byte(`{"error":"boom"}`))
		}))
		defer ts.Close()

		result, err := ForwardAndParseResponse(context.Background(), ts.URL, "GET", "/api/test", map[string]interface{}{}, []string{}, "", "TestTool")
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if !result.IsError {
			t.Error("expected error result")
		}
	})

	t.Run("upstream error 404", func(t *testing.T) {
		ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			w.WriteHeader(http.StatusNotFound)
			w.Write([]byte(`{"error":"not found"}`))
		}))
		defer ts.Close()

		result, err := ForwardAndParseResponse(context.Background(), ts.URL, "GET", "/api/test", map[string]interface{}{}, []string{}, "", "TestTool")
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if !result.IsError {
			t.Error("expected error result for 404")
		}
	})
}

